1	export interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	export interface QuoteInput {
9	  items: Item[];
10	  yearsWithMHPCO?: number;
11	  firstInsurance?: boolean;
12	  followUp?: boolean;
13	}
14	
15	export interface QuoteResult {
16	  premium: number;
17	}
18	
19	const PROCESSING_FEE = 5;
20	const DEFAULT_BASE_PREMIUM = 100;
21	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	  rune: 25,
26	  moonstone: 25,
27	};
28	
29	const CURSE_SURCHARGE_RATE = 0.5;
30	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
31	
32	function unmodifiedBasePremiumFor(item: Item): number {
33	  return BASE_PREMIUM_BY_TYPE[item.type] ?? DEFAULT_BASE_PREMIUM;
34	}
35	
36	function basePremiumFor(item: Item): number {
37	  const base = unmodifiedBasePremiumFor(item);
38	  const highEnchantmentSurcharge =
39	    item.enchantment !== undefined && item.enchantment >= 5
40	      ? HIGH_ENCHANTMENT_SURCHARGE_RATE
41	      : 0;
42	  const curseSurcharge = item.cursed ? CURSE_SURCHARGE_RATE : 0;
43	  return base * (1 + highEnchantmentSurcharge + curseSurcharge);
44	}
45	
46	const BLOCK_SIZE = 3;
47	const BLOCK_PREMIUM = 60;
48	
49	const LOYALTY_DISCOUNT_RATE = 0.2;
50	const LOYALTY_MIN_YEARS = 2;
51	
52	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
53	
54	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
55	
56	function rateOfBaseWhen(
57	  condition: boolean | undefined,
58	  basePremium: number,
59	  rate: number,
60	): number {
61	  return condition ? basePremium * rate : 0;
62	}
63	
64	function groupByType(items: Item[]): Map<string, Item[]> {
65	  const groups = new Map<string, Item[]>();
66	  for (const item of items) {
67	    const group = groups.get(item.type) ?? [];
68	    group.push(item);
69	    groups.set(item.type, group);
70	  }
71	  return groups;
72	}
73	
74	function basePremiumForGroup(group: Item[]): number {
75	  if (group.length === BLOCK_SIZE) {
76	    return BLOCK_PREMIUM;
77	  }
78	  return group.reduce((sum, item) => sum + basePremiumFor(item), 0);
79	}
80	
81	export interface Damage {
82	  itemType: string;
83	  amount: number;
84	}
85	
86	export interface Incident {
87	  cause: string;
88	  damages: Damage[];
89	}
90	
91	export interface ClaimResult {
92	  payout: number;
93	  remainingCap: number;
94	}
95	
96	const DEDUCTIBLE = 100;
97	const CAP_MULTIPLIER = 2;
98	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
99	  sword: 1000,
100	  amulet: 600,
101	  staff: 800,
102	  potion: 400,
103	  rune: 250,
104	  moonstone: 250,
105	};
106	
107	function insuranceValueFor(item: Item): number {
108	  return INSURANCE_VALUE_BY_TYPE[item.type] ?? 0;
109	}
110	
111	function capFor(items: Item[]): number {
112	  const insuranceSum = items.reduce(
113	    (sum, item) => sum + insuranceValueFor(item),
114	    0,
115	  );
116	  return CAP_MULTIPLIER * insuranceSum;
117	}
118	
119	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
120	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
121	
122	function reimbursableFor(item: Item | undefined, amount: number): number {
123	  if (
124	    item?.enchantment !== undefined &&
125	    item.enchantment >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD
126	  ) {
127	    return amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
128	  }
129	  return amount;
130	}
131	
132	export function claim(items: Item[], incident: Incident): ClaimResult {
133	  const payout = incident.damages.reduce((sum, damage) => {
134	    const item = items.find((candidate) => candidate.type === damage.itemType);
135	    const reimbursable = reimbursableFor(item, damage.amount);
136	    return sum + Math.max(0, reimbursable - DEDUCTIBLE);
137	  }, 0);
138	  return { payout, remainingCap: capFor(items) - payout };
139	}
140	
141	export function quote(input: QuoteInput): QuoteResult {
142	  const groups = [...groupByType(input.items).values()];
143	  const basePremium = groups.reduce(
144	    (sum, group) => sum + basePremiumForGroup(group),
145	    0,
146	  );
147	
148	  const unmodifiedBasePremium = input.items.reduce(
149	    (sum, item) => sum + unmodifiedBasePremiumFor(item),
150	    0,
151	  );
152	
153	  const firstInsuranceSurcharge = rateOfBaseWhen(
154	    input.firstInsurance,
155	    unmodifiedBasePremium,
156	    FIRST_INSURANCE_SURCHARGE_RATE,
157	  );
158	
159	  const followUpDiscount = rateOfBaseWhen(
160	    input.followUp,
161	    unmodifiedBasePremium,
162	    FOLLOW_UP_DISCOUNT_RATE,
163	  );
164	
165	  const qualifiesForLoyalty =
166	    input.yearsWithMHPCO !== undefined &&
167	    input.yearsWithMHPCO >= LOYALTY_MIN_YEARS;
168	  const loyaltyDiscount = rateOfBaseWhen(
169	    qualifiesForLoyalty,
170	    unmodifiedBasePremium,
171	    LOYALTY_DISCOUNT_RATE,
172	  );
173	
174	  const surcharges = firstInsuranceSurcharge;
175	  const discounts = loyaltyDiscount + followUpDiscount;
176	
177	  const rawPremium = basePremium + surcharges - discounts + PROCESSING_FEE;
178	
179	  return {
180	    premium: Math.ceil(rawPremium),
181	  };
182	}
